import React, { useState } from 'react';

const exercises = ['Push Ups', 'Running', 'Plank'];
const types = ['Repetition', 'Duration'];

function ExerciseSelect({ onStart }) {
  const [selectedExercise, setSelectedExercise] = useState(null);

  const handleTypeSelect = (type) => {
    if (selectedExercise) {
      onStart(selectedExercise, type);
    }
  };

  return (
    <div>
      <h2>Select Exercise</h2>
      {exercises.map((exercise) => (
        <button key={exercise} onClick={() => setSelectedExercise(exercise)}>
          {exercise} {selectedExercise === exercise ? '(selected)' : ''}
        </button>
      ))}

      <h2>Select Type</h2>
      {types.map((type) => (
        <button key={type} onClick={() => handleTypeSelect(type)}>
          {type}
        </button>
      ))}
    </div>
  );
}

export default ExerciseSelect;
